export function createFailureDetector(): FailureDetector {
  return {
    detectBlockingFailures(task: ProjectTask): Result<BlockingFailure[], ErrorEnvelope> {
      const failures: BlockingFailure[] = [];
      const now = new Date().toISOString();

      // Spec required in Phase 2+
      const hasSpec = task.children.some(
        c => c.type === 'spec' && c.content && c.content.trim().length > 0,
      );
      if (!hasSpec && ['spec_drafting', 'spec_refinement'].includes(task.status)) {
        failures.push({
          id: `${task.id}-no-spec`,
          category: 'spec_issue',
          message: 'No spec document attached to this task',
          affectedGates: ['pm_approval', 'arch_pm_signoff'],
          autoClears: true,
          detectedAt: now,
        });
      }

      // Architecture notes required in Phase 3+
      const hasArch = task.children.some(
        c => c.type === 'architecture_notes' && c.content && c.content.trim().length > 0,
      );
      if (!hasArch && ['tech_spec', 'issue_breakdown', 'development'].includes(task.status)) {
        failures.push({
          id: `${task.id}-no-arch`,
          category: 'architecture_issue',
          message: 'No architecture notes attached to this task',
          affectedGates: ['arch_pm_signoff', 'arch_review'],
          autoClears: true,
          detectedAt: now,
        });
      }

      // Rejected gates
      const gateNames = Object.keys(task.gates) as GateName[];
      for (const gateName of gateNames) {
        const gate = task.gates[gateName];
        if (gate && gate.status === 'rejected') {
          failures.push({
            id: `${task.id}-gate-rejected-${gateName}`,
            category: 'spec_issue',
            message: `Gate "${gateName}" was rejected${gate.rejectionReason ? `: ${gate.rejectionReason}` : ''}`,
            affectedGates: [gateName],
            autoClears: false,
            detectedAt: gate.rejectedAt ?? now,
          });
        }
      }

      // Subtasks required before development
      if (task.status === 'development') {
        const hasSubtasks = task.children.some(c => c.type === 'subtask');
        if (!hasSubtasks) {
          failures.push({
            id: `${task.id}-no-subtasks`,
            category: 'missing_dependency',
            message: 'No subtasks defined for development stage',
            affectedGates: ['arch_review'],
            autoClears: true,
            detectedAt: now,
          });
        }
      }

      return Ok(failures);
    },

    isBlocked(task: ProjectTask): BlockedState {
      const result = this.detectBlockingFailures(task);
      if (!result.ok) return { blocked: false, reasons: [], failures: [] };

      const active = result.value.filter(f => !f.resolvedAt);
      return { blocked: active.length > 0, reasons: active.map(f => f.message), failures: active };
    },

    async checkSourceAvailability(): Promise<SourceAvailability[]> {
      const now = new Date().toISOString();
      const results: SourceAvailability[] = [];

      const githubToken = process.env['GITHUB_TOKEN'];
      if (githubToken) {
        try {
          const response = await fetch('https://api.github.com/rate_limit', {
            headers: { Authorization: `Bearer ${githubToken}` },
            signal: AbortSignal.timeout(5000),
          });
          results.push({ source: 'github', available: response.ok, stale: false, lastChecked: now });
        } catch (error) {
          results.push({
            source: 'github',
            available: false,
            stale: false,
            lastChecked: now,
            error: error instanceof Error ? error.message : 'Unknown error',
          });
        }
      } else {
        results.push({ source: 'github', available: false, stale: false, lastChecked: now, error: 'GITHUB_TOKEN not configured' });
      }

      const linearKey = process.env['LINEAR_API_KEY'];
      if (linearKey) {
        try {
          const response = await fetch('https://api.linear.app/graphql', {
            method: 'POST',
            headers: { Authorization: linearKey, 'Content-Type': 'application/json' },
            body: JSON.stringify({ query: '{ viewer { id } }' }),
            signal: AbortSignal.timeout(5000),
          });
          results.push({ source: 'linear', available: response.ok, stale: false, lastChecked: now });
        } catch (error) {
          results.push({
            source: 'linear',
            available: false,
            stale: false,
            lastChecked: now,
            error: error instanceof Error ? error.message : 'Unknown error',
          });
        }
      } else {
        results.push({ source: 'linear', available: false, stale: false, lastChecked: now, error: 'LINEAR_API_KEY not configured' });
      }

      return results;
    },

    getFailuresForGate(task: ProjectTask, gate: GateName): BlockingFailure[] {
      const result = this.detectBlockingFailures(task);
      if (!result.ok) return [];

      const blockingCategories = GATE_BLOCKING_CATEGORIES[gate] ?? [];
      return result.value.filter(
        f =>
          !f.resolvedAt &&
          (f.affectedGates.length === 0 ||
            f.affectedGates.includes(gate) ||
            blockingCategories.includes(f.category)),
      );
    },
  };
}

function isPriorGatesApproved(
  task: ProjectTask,
  gate: GateName,
  policy: GatePolicy,
): boolean {
  const idx = GATE_ORDER.indexOf(gate);
  for (let i = 0; i < idx; i++) {
    const prior = GATE_ORDER[i];
    if (!prior) continue;
    // Disabled gates auto-pass; no approval needed to advance past them.
    if (policy[prior] === 'disabled') continue;
    const status = task.gates[prior]?.status;
    // Optional gates can also be skipped (status stays 'not_ready' but the
    // task advances past them if the user opts out).
    if (policy[prior] === 'optional' && status === 'not_ready') continue;
    if (status !== 'approved') return false;
  }
  return true;
}

function checkGateSequencing(events: AuditEvent[]): ComplianceCheck {
  const approvals = events
    .filter(e => e.type === 'gate_approved' && typeof e.gate === 'string')
    .sort((a, b) => a.timestamp.localeCompare(b.timestamp));

  if (approvals.length === 0) {
    return {
      id:      'gate_sequencing',
      name:    'Gate sequence',
      status:  'na',
      message: 'No gates approved on this task yet.',
    };
  }

  if (approvals.length < 2) {
    // A single approval can't be "out of order" — insufficient signal.
    return {
      id:      'gate_sequencing',
      name:    'Gate sequence',
      status:  'pass',
      message: `Single gate approval (${approvals[0]?.gate}) — no ordering to check.`,
    };
  }

  const outOfOrder: AuditEvent[] = [];
  for (let i = 1; i < approvals.length; i++) {
    const prev = gateRank(approvals[i - 1]?.gate);
    const curr = gateRank(approvals[i]?.gate);
    if (prev >= 0 && curr >= 0 && curr < prev) {
      const approval = approvals[i];
      if (approval) outOfOrder.push(approval);
    }
  }

  if (outOfOrder.length === 0) {
    const seq = approvals.map(a => a.gate).join(' → ');
    return {
      id:      'gate_sequencing',
      name:    'Gate sequence',
      status:  'pass',
      message: `Approvals followed canonical order: ${seq}.`,
    };
  }

  return {
    id:      'gate_sequencing',
    name:    'Gate sequence',
    status:  'warn',
    message: `${outOfOrder.length} approval${outOfOrder.length === 1 ? '' : 's'} out of canonical order (pm → arch_pm → arch).`,
    evidence: outOfOrder.map(e => e.id),
  };
}

function gateRank(gate: string | undefined): number {
  if (!gate) return -1;
  return (GATE_ORDER as readonly string[]).indexOf(gate);
}

function defaultMessage(trigger: NotificationTrigger, gate?: GateName): string {
  switch (trigger) {
    case 'task_created':    return 'A new task has been submitted';
    case 'gate_ready':      return `Gate "${gate ?? 'unknown'}" is ready for review`;
    case 'gate_approved':   return `Gate "${gate ?? 'unknown'}" was approved`;
    case 'gate_rejected':   return `Gate "${gate ?? 'unknown'}" was rejected`;
    case 'blocking_failure': return 'A blocking failure was detected on this task';
    case 'dev_started':     return 'Development has started on a subtask';
    case 'pr_linked':       return 'A PR has been linked to this task';
  }
}

export function Ok<T>(value: T): Result<T, never> {
  return { ok: true, value };
}

export function map<T, U, E>(
  result: Result<T, E>,
  fn: (value: T) => U,
): Result<U, E> {
  return result.ok ? Ok(fn(result.value)) : result;
}

function deriveWorstGateState(gateStates: Array<{ state: string }>): 'rejected' | 'not_ready' | 'approved' | 'no_gates' {
  if (gateStates.length === 0) return 'no_gates';

  const rejected = gateStates.some(g => g.state === 'rejected');
  if (rejected) return 'rejected';

  const ready = gateStates.some(g => g.state === 'ready');
  const approved = gateStates.some(g => g.state === 'approved');
  if (ready && approved) return 'not_ready';

  return 'approved';
}

export function getApproversForGate(
  registry: UserRegistry,
  gate: string,
): Result<string[], ErrorEnvelope> {
  const roles = GATE_APPROVER_ROLES[gate] ?? [];
  const ids = new Set<string>();
  for (const role of roles) {
    for (const user of registry.byRole(role)) {
      ids.add(user.id);
    }
  }
  return Ok(Array.from(ids));
}

const approveGate = (t: ProjectTask, gate: 'pm_approval' | 'arch_pm_signoff') => {
  const readyRole = gate === 'pm_approval' ? 'submitter' : 'tech_lead';
  const approveRole = gate === 'pm_approval' ? 'product_manager' : 'architect';
  const r1 = machine.transition(t, gate, { actorId: 'u', actorRole: readyRole, action: 'ready' });
  if (!r1.ok) throw new Error(`ready ${gate} failed: ${r1.error.message}`);
  const r2 = machine.transition(r1.value.task, gate, { actorId: 'a', actorRole: approveRole, action: 'approve' });
  if (!r2.ok) throw new Error(`approve ${gate} failed: ${r2.error.message}`);
  return r2.value.task;
};

