export function getIdentityProvider(): IdentityProvider {
  // M8: until MSAL has actually initialised, the AAD provider has no account
  // to read — fall back to manual so the dev-mode bypass path is fully
  // transparent (no flash of "Sign in" UI).
  if (!isMsalEnabled()) {
    return manualIdentityProvider;
  }

  switch (configured) {
    case 'azuread':
      return azureADIdentityProvider;
    case 'manual':
    default:
      return manualIdentityProvider;
  }
}

resolve(defaultRole: Role | string): IdentityResolution {
  const m365 = readM365();
  const id = resolveId();
  const role = resolveRole(defaultRole);
  const isFromProvider = Boolean(m365?.displayName) || Boolean(localStorage.getItem(KEY_LINEAR_NAME));
  const roleIsLocked = Boolean(m365?.forgeRole);

  return {
    actor: {
      id,
      name: id,
      email: m365?.email,
      isFromProvider,
    },
    role,
    availableRoles: DEFAULT_ROLES,
    roleIsLocked,
  };
},

