export async function getAccessToken(
  instance: PublicClientApplication | null,
  scopes: readonly string[],
): Promise<string | null> {
  if (!instance) return null;

  const account: AccountInfo | null =
    instance.getActiveAccount() ?? instance.getAllAccounts()[0] ?? null;

  if (!account) return null;

  try {
    const result = await instance.acquireTokenSilent({
      account,
      scopes: [...scopes],
    });
    return result.accessToken;
  } catch (err) {
    if (err instanceof InteractionRequiredAuthError) {
      // Fallback: redirect to AAD login; returns void (page navigates away)
      await instance.acquireTokenRedirect({
        account,
        scopes: [...scopes],
      });
      // acquireTokenRedirect navigates away; returning null is safe here
      return null;
    }
    console.error('[msal] acquireTokenSilent failed:', err);
    return null;
  }
}

export function useMsalInstance(): MsalContextValue {
