}

export function useActor(defaultRole = 'architect') {
  const { actor, role, setActorId, setRole, roleIsLocked } = useIdentity(defaultRole);

  return {
    actorId: actor.id,
    setActorId,
    actorRole: role,
    setActorRole: setRole,
    isFromProvider: actor.isFromProvider,
    /** True if the current role is derived from Azure AD / identity provider */
    roleFromAzureAD: roleIsLocked,
  };
}

export function useIdentity(defaultRole: Role | string = 'architect'): UseIdentityReturn {
  const provider = getIdentityProvider();
  const [resolution, setResolution] = useState(() => provider.resolve(defaultRole));
  const { instance, scopes } = useMsalInstance();

  // Re-resolve if external state (M365 login) changes mid-session.
  useEffect(() => {
    setResolution(provider.resolve(defaultRole));
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const setActorId = useCallback(
    (id: string) => {
      provider.setActorId(id);
      setResolution((prev) => ({ ...prev, actor: { ...prev.actor, id, name: id } }));
    },
    [provider],
  );

  const setRole = useCallback(
    (role: Role | string) => {
      provider.setRole(role);
      setResolution((prev) => ({ ...prev, role }));
    },
    [provider],
  );

  const getToken = useCallback(
    () => getAccessToken(instance, scopes),
    [instance, scopes],
  );

  return {
    actor: resolution.actor,
    role: resolution.role,
    setActorId,
    setRole,
    availableRoles: resolution.availableRoles,
    roleIsLocked: resolution.roleIsLocked,
    getToken,
  };
}

export function isAuthorized(
  gate: GateName,
  action: GateAction,
  actorRole: string | null | undefined,
): boolean {
  if (!actorRole) return false;
  const allowedRoles = GATE_ALLOWED_ROLES[gate][action];
  return (allowedRoles as readonly string[]).includes(actorRole);
}

export function deriveWorstGateState(tasks: Array<{ gates: Record<string, GateRecord> }>): WorstGateState {
  if (!tasks || tasks.length === 0) {
    return 'no_gates';
  }

  // Flatten all gates across all tasks
  const allGates: Array<{ gate: string; state: GateState }> = [];
  const GATE_ORDER = ['pm_approval', 'arch_pm_signoff', 'arch_review'];

  for (const task of tasks) {
    if (!task.gates) continue;
    for (const [gateName, gateRecord] of Object.entries(task.gates)) {
      if (gateRecord && typeof gateRecord === 'object' && 'state' in gateRecord) {
        allGates.push({ gate: gateName, state: gateRecord.state });
      }
    }
  }

  if (allGates.length === 0) {
    return 'no_gates';
  }

  // Check for rejected gates (red)
  if (allGates.some(g => g.state === 'rejected')) {
    return 'rejected';
  }

  // Review B-2 T7-2: a project where every gate is `not_ready` (no actor
  // has yet approved/rejected/marked-ready anything) was previously
  // returning 'approved' — a green border on a brand-new untouched
  // project. Treat zero-progress projects as 'no_gates' (gray) instead.
  const hasAnyProgress = allGates.some(
    g => g.state === 'approved' || g.state === 'ready' || g.state === 'rejected',
  );
  if (!hasAnyProgress) return 'no_gates';

  // Check for blocking not_ready (yellow):
  // A gate is blocking if any prior gate in the sequence is approved
  const readyGates = allGates.filter(g => g.state === 'ready');
  const approvedGates = allGates.filter(g => g.state === 'approved');

  if (readyGates.length > 0 && approvedGates.length > 0) {
    // At least one prior gate was approved, so a not_ready is blocking
    return 'not_ready';
  }

  // All clean (no rejections, no blocking not_ready)
  return 'approved';
}

