export function createActivityFeed(
  broadcast?: (event: string, data: unknown) => void,
): ActivityFeed {
  const events = new Map<string, ActivityEvent>();
  /** Mutable connected state per task */
  const connectedState = new Map<string, ConnectedState>();

  function getOrCreateState(taskId: string): ConnectedState {
    if (!connectedState.has(taskId)) {
      connectedState.set(taskId, { taskId, eventCount: 0 });
    }
    return connectedState.get(taskId)!;
  }

  function updateConnectedState(event: ActivityEvent): void {
    const state = getOrCreateState(event.taskId);
    state.lastActivity = event.timestamp;
    state.eventCount++;

    switch (event.kind) {
      case 'pr_opened':
      case 'pr_updated':
        state.githubPrNumber = event.payload['prNumber'] as number | undefined;
        state.githubPrUrl = event.payload['prUrl'] as string | undefined;
        state.githubPrStatus = 'open';
        break;
      case 'pr_merged':
        state.githubPrStatus = 'merged';
        break;
      case 'pr_closed':
        state.githubPrStatus = 'closed';
        break;
      case 'ci_started':
        state.ciStatus = 'running';
        break;
      case 'ci_passed':
        state.ciStatus = 'passed';
        break;
      case 'ci_failed':
        state.ciStatus = 'failed';
        break;
      case 'linear_issue_linked':
        state.linearIssueId = event.payload['issueId'] as string | undefined;
        break;
      case 'agent_started':
        state.agentSessionId = event.payload['agentSessionId'] as string | undefined;
        break;
    }

    connectedState.set(event.taskId, state);
  }

  return {
    record(event: Omit<ActivityEvent, 'id' | 'timestamp'>): ActivityEvent {
      const full: ActivityEvent = {
        ...event,
        id: `activity_${uuidv4()}`,
        timestamp: new Date().toISOString(),
      };
      events.set(full.id, full);
      updateConnectedState(full);
      broadcast?.('activity', { taskId: full.taskId, event: full });
      return full;
    },

    getEvents(taskId: string, options = {}): ActivityEvent[] {
      let results = Array.from(events.values()).filter(e => e.taskId === taskId);

      if (options.since) {
        results = results.filter(e => e.timestamp >= options.since!);
      }

      results.sort((a, b) => b.timestamp.localeCompare(a.timestamp));

      if (options.limit) {
        results = results.slice(0, options.limit);
      }

      return results;
    },

    getConnectedState(taskId: string): ConnectedState {
      return getOrCreateState(taskId);
    },
  };
}

function setupWebSocket(wss: WebSocketServer): void {
  wss.on('connection', (ws: WebSocket) => {
    // Send welcome message
    ws.send(JSON.stringify({
      event: 'connected',
      data: { message: 'Connected to Forge API WebSocket' },
      timestamp: new Date().toISOString(),
    }));

    // Handle incoming messages
    ws.on('message', async (message: Buffer) => {
      try {
        const data = JSON.parse(message.toString());

        // Handle project scaffolding requests
        if (data.event === 'scaffold_project') {
          const { scaffoldProject } = await import('./project-scaffolder.js');
          const config = data.config;

          // Validate config
          if (!config || !config.name || !config.version || !config.owner || !config.description) {
            ws.send(JSON.stringify({
              event: 'scaffold_error',
              data: { message: 'Invalid project configuration' },
              timestamp: new Date().toISOString(),
            }));
            return;
          }

          // Start scaffolding with progress updates
          const targetDir = process.cwd();
          const result = await scaffoldProject(config, targetDir, (progress) => {
            ws.send(JSON.stringify({
              event: 'scaffold_progress',
              data: progress,
              timestamp: new Date().toISOString(),
            }));
          });

          if (result.ok) {
            ws.send(JSON.stringify({
              event: 'scaffold_complete',
              data: result.value,
              timestamp: new Date().toISOString(),
            }));
          } else {
            ws.send(JSON.stringify({
              event: 'scaffold_error',
              data: result.error,
              timestamp: new Date().toISOString(),
            }));
          }
        } else {
          // Echo back for other messages
          ws.send(JSON.stringify({
            event: 'echo',
            data,
            timestamp: new Date().toISOString(),
          }));
        }
      } catch (error) {
        ws.send(JSON.stringify({
          event: 'error',
          data: { message: 'Invalid message format' },
          timestamp: new Date().toISOString(),
        }));
      }
    });

    ws.on('close', () => {
      // Client disconnected
    });

    ws.on('error', () => {
      // WebSocket error occurred
    });
  });
}

function writeFile(filePath: string, content: string): Result<void, FileSystemError> {
  try {
    fs.writeFileSync(filePath, content, "utf-8");
    return Ok(undefined);
  } catch (e: unknown) {
    const msg = e instanceof Error ? e.message : String(e);
    return Err(
      createErrorEnvelope("bootstrap_write_failed", `Failed to write file: ${filePath} — ${msg}`, {
        path: filePath,
      }),
    );
  }
}

export function getErrorGuidance(
  errorCode: string,
  context: ErrorContext = {},
): ErrorGuidance {
  // Use Object.prototype.hasOwnProperty to avoid prototype pollution issues
  const guidance = Object.prototype.hasOwnProperty.call(ERROR_GUIDANCE_CATALOG, errorCode)
    ? ERROR_GUIDANCE_CATALOG[errorCode]
    : undefined;

  if (!guidance) {
    return {
      suggestions: ["Check the error message for details", "Run 'forge doctor' to diagnose common issues"],
      exampleCommands: ["forge doctor", "forge --help"],
      documentationLinks: ["https://github.com/navistone/engineering-agent-standards"],
    };
  }

  // Replace context placeholders in suggestions and commands
  const suggestions = guidance.suggestions.map(s => replaceContextPlaceholders(s, context));
  const exampleCommands = guidance.exampleCommands.map(c => replaceContextPlaceholders(c, context));

  return {
    suggestions,
    exampleCommands,
    documentationLinks: guidance.documentationLinks,
  };
}

export function createErrorEnvelope(
  error: string,
  message: string,
  details?: Record<string, unknown>,
): ErrorEnvelope {
  // Extract context for error guidance from details
  const context: Record<string, string | number | boolean | undefined> = {};
  if (details) {
    for (const [key, value] of Object.entries(details)) {
      if (typeof value === "string" || typeof value === "number" || typeof value === "boolean") {
        context[key] = value;
      }
    }
  }

  // Get error recovery guidance
  const guidance = getErrorGuidance(error, context);

  // Merge guidance into details
  const enhancedDetails = {
    ...details,
    guidance: {
      suggestions: guidance.suggestions,
      exampleCommands: guidance.exampleCommands,
      documentationLinks: guidance.documentationLinks,
    },
  };

  return {
    error,
    message,
    timestamp: new Date().toISOString(),
    traceId: generateTraceId(),
    details: enhancedDetails,
  };
}

export function generateTraceId(): string {
  return uuidv4();
}

