export async function scaffoldProject(
  config: ScaffoldConfig,
  targetDir: string,
  onProgress: ProgressCallback,
): Promise<Result<ScaffoldResult, ErrorEnvelope>> {
  const createdFiles: string[] = [];
  const createdDirectories: string[] = [];
  const projectPath = path.join(targetDir, config.name);

  try {
    // Step 1: Create project directory
    onProgress({
      step: 'create_directory',
      message: 'Creating project directory...',
      progress: 10,
      timestamp: new Date().toISOString(),
    });

    await fs.mkdir(projectPath, { recursive: true });
    createdDirectories.push(projectPath);

    // Step 2: Create .specs directory
    onProgress({
      step: 'create_specs_dir',
      message: 'Creating .specs directory...',
      progress: 20,
      timestamp: new Date().toISOString(),
    });

    const specsDir = path.join(projectPath, '.specs');
    await fs.mkdir(specsDir, { recursive: true });
    createdDirectories.push(specsDir);

    // Step 3: Create index.yaml manifest
    onProgress({
      step: 'create_manifest',
      message: 'Generating index.yaml manifest...',
      progress: 30,
      timestamp: new Date().toISOString(),
    });

    const manifest = generateManifest(config);
    const manifestPath = path.join(projectPath, 'index.yaml');
    await fs.writeFile(manifestPath, manifest, 'utf-8');
    createdFiles.push(manifestPath);

    // Step 4: Write OpenAPI spec if provided
    if (config.openApiSpec) {
      onProgress({
        step: 'write_openapi',
        message: 'Writing OpenAPI specification...',
        progress: 50,
        timestamp: new Date().toISOString(),
      });

      const openApiPath = path.join(specsDir, 'openapi.yaml');
      await fs.writeFile(openApiPath, config.openApiSpec, 'utf-8');
      createdFiles.push(openApiPath);
    }

    // Step 5: Write Prisma schema if provided
    if (config.prismaSchema) {
      onProgress({
        step: 'write_prisma',
        message: 'Writing Prisma schema...',
        progress: 60,
        timestamp: new Date().toISOString(),
      });

      const prismaDir = path.join(projectPath, 'prisma');
      await fs.mkdir(prismaDir, { recursive: true });
      createdDirectories.push(prismaDir);

      const prismaPath = path.join(prismaDir, 'schema.prisma');
      await fs.writeFile(prismaPath, config.prismaSchema, 'utf-8');
      createdFiles.push(prismaPath);
    }

    // Step 6: Create basic project structure
    onProgress({
      step: 'create_structure',
      message: 'Creating project structure...',
      progress: 70,
      timestamp: new Date().toISOString(),
    });

    const srcDir = path.join(projectPath, 'src');
    await fs.mkdir(srcDir, { recursive: true });
    createdDirectories.push(srcDir);

    const testsDir = path.join(projectPath, 'tests');
    await fs.mkdir(testsDir, { recursive: true });
    createdDirectories.push(testsDir);

    const sdkDir = path.join(projectPath, 'sdk');
    await fs.mkdir(sdkDir, { recursive: true });
    createdDirectories.push(sdkDir);

    const scriptsDir = path.join(projectPath, 'scripts');
    await fs.mkdir(scriptsDir, { recursive: true });
    createdDirectories.push(scriptsDir);

    const docsDir = path.join(projectPath, 'docs');
    await fs.mkdir(docsDir, { recursive: true });
    createdDirectories.push(docsDir);

    // Step 7: Create package.json
    onProgress({
      step: 'create_package',
      message: 'Generating package.json...',
      progress: 80,
      timestamp: new Date().toISOString(),
    });

    const packageJson = generatePackageJson(config);
    const packagePath = path.join(projectPath, 'package.json');
    await fs.writeFile(packagePath, packageJson, 'utf-8');
    createdFiles.push(packagePath);

    // Step 8: Create README
    onProgress({
      step: 'create_readme',
      message: 'Generating README.md...',
      progress: 85,
      timestamp: new Date().toISOString(),
    });

    const readme = generateReadme(config);
    const readmePath = path.join(projectPath, 'README.md');
    await fs.writeFile(readmePath, readme, 'utf-8');
    createdFiles.push(readmePath);

    // Step 9: Create rules.md
    onProgress({
      step: 'create_rules',
      message: 'Generating rules.md...',
      progress: 90,
      timestamp: new Date().toISOString(),
    });

    const rules = generateRules(config);
    const rulesPath = path.join(projectPath, 'rules.md');
    await fs.writeFile(rulesPath, rules, 'utf-8');
    createdFiles.push(rulesPath);

    // Step 10: Create constitution.md
    onProgress({
      step: 'create_constitution',
      message: 'Generating constitution.md...',
      progress: 95,
      timestamp: new Date().toISOString(),
    });

    const constitution = generateConstitution(config);
    const constitutionPath = path.join(projectPath, 'constitution.md');
    await fs.writeFile(constitutionPath, constitution, 'utf-8');
    createdFiles.push(constitutionPath);

    // Step 11: Complete
    onProgress({
      step: 'complete',
      message: 'Project scaffolding complete!',
      progress: 100,
      timestamp: new Date().toISOString(),
    });

    return Ok({
      success: true,
      projectPath,
      createdFiles,
      createdDirectories,
      nextSteps: [
        'cd ' + config.name,
        'pnpm install',
        'make sync',
        'make validate',
      ],
    });
  } catch (error) {
    return Err(
      createErrorEnvelope(
        'project_scaffold_failed',
        `Failed to scaffold project: ${error instanceof Error ? error.message : String(error)}`,
      ),
    );
  }
}

export function Err<E>(error: E): Result<never, E> {
  return { ok: false, error };
}

export function Ok<T>(value: T): Result<T, never> {
  return { ok: true, value };
}

export function map<T, U, E>(
  result: Result<T, E>,
  fn: (value: T) => U,
): Result<U, E> {
  return result.ok ? Ok(fn(result.value)) : result;
}

export function createActivityRoutes(deps: AppDependencies): Router {
  const router = Router();

  if (!deps.activityFeed) {
    router.use((_req, res) => {
      res.status(503).json({ error: { error: 'activity_unavailable', message: 'Activity feed not configured' } });
    });
    return router;
  }

  const feed = deps.activityFeed;

  /** GET /api/activity/:taskId?limit=50&since=ISO */
  router.get('/:taskId', (req, res) => {
    const taskId = typeof req.params['taskId'] === 'string' ? req.params['taskId'] : '';
    const limit = req.query['limit'] ? parseInt(req.query['limit'] as string, 10) : 50;
    const since = typeof req.query['since'] === 'string' ? req.query['since'] : undefined;
    res.json(feed.getEvents(taskId, { limit, since }));
  });

  /** GET /api/activity/:taskId/connected */
  router.get('/:taskId/connected', (req, res) => {
    const taskId = typeof req.params['taskId'] === 'string' ? req.params['taskId'] : '';
    res.json(feed.getConnectedState(taskId));
  });

  /** POST /api/activity/:taskId — { source, kind, summary, url?, actorId?, payload? } */
  router.post('/:taskId', (req, res) => {
    const taskId = typeof req.params['taskId'] === 'string' ? req.params['taskId'] : '';
    const body = req.body as Record<string, unknown>;

    if (!body['source'] || !body['kind'] || !body['summary']) {
      res.status(400).json({ error: { error: 'missing_fields', message: 'source, kind, summary are required' } });
      return;
    }

    // Phase 2: server-resolved identity wins. Falls back to body.actorId
    // for legacy clients (e.g. Linear webhook payloads) that arrive
    // without a Forge x-actor-id header.
    const identity = getIdentity(req);
    const bodyActorId = typeof body['actorId'] === 'string' ? body['actorId'] : undefined;

    const event = feed.record({
      taskId,
      source: body['source'] as ActivityEventSource,
      kind: body['kind'] as ActivityEventKind,
      summary: body['summary'] as string,
      url: typeof body['url'] === 'string' ? body['url'] : undefined,
      actorId: identity?.actor.id ?? bodyActorId,
      payload: (body['payload'] as Record<string, unknown>) ?? {},
    });

    res.status(201).json(event);
  });

  return router;
}

export function getIdentity(req: Request): ResolvedIdentity | null {
  return (req as WithIdentity).forgeIdentity ?? null;
}

export function authHeaders(useAlternate = false): Record<string, string> {
  if (!TOKEN) return {};
  if (useAlternate) {
    return { 'X-Forge-Service-Token': TOKEN };
  }
  return { Authorization: `Bearer ${TOKEN}` };
}

