void (async () => {
  try {
    // Convert relative URL to absolute WebSocket URL
    let wsUrl = url;
    if (url.startsWith('/')) {
      const protocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
      wsUrl = `${protocol}//${window.location.host}${url}`;
    }

    // Acquire a fresh access token if a provider was supplied. We do
    // this on every connect (including reconnects) so a token that
    // expired between drops gets refreshed before the new handshake.
    let token: string | null = null;
    if (getTokenRef.current) {
      try {
        token = await getTokenRef.current();
      } catch {
        // Token acquisition failure: open without subprotocols. The
        // server will respond 401 on the upgrade if auth is required,
        // and the existing reconnect/error machinery handles it.
        token = null;
      }
    }

    if (isUnmountingRef.current) return;

    // M6: encode bearer in Sec-WebSocket-Protocol when present.
    // ['bearer', '<token>'] — server reads the second value.
    const ws =
      token !== null
        ? new WebSocket(wsUrl, ['bearer', token])
        : new WebSocket(wsUrl);

    ws.onopen = () => {
      if (isUnmountingRef.current) {
        ws.close();
        return;
      }
      setIsConnected(true);
      reconnectAttemptsRef.current = 0;
      onConnect?.();
    };

    ws.onmessage = (event) => {
      if (isUnmountingRef.current) return;
      try {
        const message: WebSocketMessage = JSON.parse(event.data);
        setLastMessage(message);
        onMessage?.(message);
      } catch {
        // Silently ignore parse errors
      }
    };

    ws.onclose = () => {
      setIsConnected(false);
      wsRef.current = null;

      // Don't reconnect if unmounting
      if (isUnmountingRef.current) return;

      onDisconnect?.();

      // Attempt to reconnect with backoff
      if (reconnectAttemptsRef.current < maxReconnectAttempts) {
        reconnectAttemptsRef.current += 1;
        const backoff = reconnectInterval * reconnectAttemptsRef.current;
        reconnectTimeoutRef.current = setTimeout(() => {
          if (!isUnmountingRef.current) {
            connect();
          }
        }, backoff);
      }
    };

    ws.onerror = (event) => {
      // Surface to caller when explicitly handled, otherwise stay
      // quiet — errors are expected when the server is unavailable.
      onError?.(event);
    };

    wsRef.current = ws;
  } catch {
    // Silently fail - WebSocket not available
  }
})();

