async function send<T>(method: string, path: string, body?: unknown): Promise<T> {
  const res = await fetch(`${BASE}${path}`, {
    method,
    headers: body ? { 'Content-Type': 'application/json' } : {},
    body: body ? JSON.stringify(body) : undefined,
  });
  if (res.status === 204) return undefined as T;
  if (!res.ok) {
    const b = await res.json().catch(() => ({})) as { error?: { message?: string } };
    throw new Error(b.error?.message ?? `Request failed: ${res.status}`);
  }
  return res.json() as Promise<T>;
}

async function checkedJson<T>(res: Response): Promise<T> {
  if (!res.ok) {
    const body = await res.json().catch(() => null) as { error?: { message?: string }; message?: string } | null;
    const msg = body?.error?.message ?? body?.message ?? `Request failed (${res.status})`;
    throw new Error(msg);
  }
  return res.json() as Promise<T>;
}

