export function getErrorGuidance(
  errorCode: string,
  context: ErrorContext = {},
): ErrorGuidance {
  // Use Object.prototype.hasOwnProperty to avoid prototype pollution issues
  const guidance = Object.prototype.hasOwnProperty.call(ERROR_GUIDANCE_CATALOG, errorCode)
    ? ERROR_GUIDANCE_CATALOG[errorCode]
    : undefined;

  if (!guidance) {
    return {
      suggestions: ["Check the error message for details", "Run 'forge doctor' to diagnose common issues"],
      exampleCommands: ["forge doctor", "forge --help"],
      documentationLinks: ["https://github.com/navistone/engineering-agent-standards"],
    };
  }

  // Replace context placeholders in suggestions and commands
  const suggestions = guidance.suggestions.map(s => replaceContextPlaceholders(s, context));
  const exampleCommands = guidance.exampleCommands.map(c => replaceContextPlaceholders(c, context));

  return {
    suggestions,
    exampleCommands,
    documentationLinks: guidance.documentationLinks,
  };
}

function replaceContextPlaceholders(text: string, context: ErrorContext): string {
  return text.replace(/\{(\w+)\}/g, (match, key) => {
    const value = context[key];
    return value !== undefined ? String(value) : match;
  });
}

export function createErrorEnvelope(
  error: string,
  message: string,
  details?: Record<string, unknown>,
): ErrorEnvelope {
  // Extract context for error guidance from details
  const context: Record<string, string | number | boolean | undefined> = {};
  if (details) {
    for (const [key, value] of Object.entries(details)) {
      if (typeof value === "string" || typeof value === "number" || typeof value === "boolean") {
        context[key] = value;
      }
    }
  }

  // Get error recovery guidance
  const guidance = getErrorGuidance(error, context);

  // Merge guidance into details
  const enhancedDetails = {
    ...details,
    guidance: {
      suggestions: guidance.suggestions,
      exampleCommands: guidance.exampleCommands,
      documentationLinks: guidance.documentationLinks,
    },
  };

  return {
    error,
    message,
    timestamp: new Date().toISOString(),
    traceId: generateTraceId(),
    details: enhancedDetails,
  };
}

export function generateTraceId(): string {
  return uuidv4();
}

async call(
  toolName: string,
  args: Record<string, unknown>,
): Promise<Result<MCPToolResult, ErrorEnvelope>> {
  if (!this.process) {
    return Err(createErrorEnvelope('github_mcp_not_connected', 'GitHub MCP client is not connected'));
  }

  try {
    const result = await this.sendRequest('tools/call', {
      name: toolName,
      arguments: args,
    });

    return Ok(result as MCPToolResult);
  } catch (error) {
    return Err(createErrorEnvelope(
      'github_mcp_call_failed',
      `GitHub MCP tool call failed: ${error instanceof Error ? error.message : String(error)}`,
    ));
  }
}

const check = (name: string, pass: boolean, detail?: string) => {
  checks.push(`${pass ? '✓' : '✗'} ${name}${detail ? ': ' + detail : ''}`);
};

async function preflight(): Promise<Result<{ codeIndexerHealth: CodeIndexerHealthResponse }, ErrorEnvelope>> {
  const [skillResult, ciResult, mrResult] = await Promise.all([
    checkSkillApiHealth(),
    checkCodeIndexerHealth(),
    checkModelRouterHealth(),
  ]);

  // All three services are hard-fail per Q6
  if (!skillResult.ok) {
    console.warn(`[orchestrator] Skill API unavailable (non-fatal): ${skillResult.error.message}`);
    return Err(createErrorEnvelope('orchestration_preflight_failed', skillResult.error.message));
  }

  if (!ciResult.ok) {
    console.warn(`[orchestrator] Code Indexer unavailable (non-fatal): ${ciResult.error.message}`);
    return Err(createErrorEnvelope('orchestration_preflight_failed', ciResult.error.message));
  }

  // Model Router is non-fatal: when the local LLM adapter (.forge/config.yaml
  // llm.provider) handles completion directly, the router is not in the
  // request path. We still issue the health probe for observability, but a
  // failure here must not block chat turns from running against LM Studio /
  // Anthropic / OpenAI directly.
  if (!mrResult.ok) {
    console.warn(`[orchestrator] Model Router unavailable (non-fatal): ${mrResult.error.message}`);
  }

  return Ok({ codeIndexerHealth: ciResult.value });
}

async function resolveCodeIndexerRepo(
  preferred?: string,
): Promise<string | string[] | null> {
  if (preferred === '*') {
    try {
      const healthResult = await checkCodeIndexerHealth();
      if (healthResult.ok && healthResult.value.indexed_repos.length > 0) {
        return healthResult.value.indexed_repos;
      }
    } catch {
      // Non-fatal — proceed without code context
    }
    return null;
  }
  if (preferred) return preferred;
  try {
    const healthResult = await checkCodeIndexerHealth();
    if (healthResult.ok && healthResult.value.indexed_repos.length === 1) {
      return healthResult.value.indexed_repos[0] ?? null;
    }
  } catch {
    // Non-fatal — proceed without code context
  }
  return null;
}

export function Err<E>(error: E): Result<never, E> {
  return { ok: false, error };
}

export function Ok<T>(value: T): Result<T, never> {
  return { ok: true, value };
}

export function map<T, U, E>(
  result: Result<T, E>,
  fn: (value: T) => U,
): Result<U, E> {
  return result.ok ? Ok(fn(result.value)) : result;
}

export function createCodeIndexerRouter(): Router {
  const router = createRouter();

  // GET /api/code-indexer/health — readiness probe pass-through.
  router.get('/health', async (_req: Request, res: Response) => {
    const result = await checkHealth();
    if (!result.ok) {
      // Upstream unreachable → surface as 503 so orchestrators treat this
      // as a dependency outage rather than an internal error.
      res.status(503).json({ error: result.error });
      return;
    }
    res.json(result.value);
  });

  // GET /api/code-indexer/explorer/info — Ladybug/Kuzu Explorer launch info.
  // Returns `available=true` iff the LadybugDB file exists AND has at least
  // one indexed repo, plus the exact `docker run kuzudb/explorer` command
  // the user can paste to open the graph viewer on localhost:7000.
  router.get('/explorer/info', async (req: Request, res: Response) => {
    const repo = typeof req.query['repo'] === 'string' ? req.query['repo'] : null;
    const result = await getExplorerInfo(repo);
    if (!result.ok) {
      res.status(502).json({ error: result.error });
      return;
    }
    res.json(result.value);
  });

  // POST /api/code-indexer/index — kick off a background index job.
  router.post('/index', async (req: Request, res: Response) => {
    const { repo_path, force_reindex } = req.body as {
      repo_path?: string;
      force_reindex?: boolean;
    };
    if (!repo_path) {
      res.status(400).json({ error: 'repo_path is required' });
      return;
    }
    const result = await startIndex(repo_path, force_reindex ?? false);
    if (!result.ok) {
      res.status(502).json({ error: result.error });
      return;
    }
    // Preserve the upstream 202 — the caller expects an accepted-not-complete
    // status so it knows to poll /status rather than treating the response
    // as the final result.
    res.status(202).json(result.value);
  });

  // GET /api/code-indexer/index/:jobId/status — poll job status.
  router.get('/index/:jobId/status', async (req: Request, res: Response) => {
    const jobId = String(req.params['jobId'] ?? '');
    const result = await getIndexStatus(jobId);
    if (!result.ok) {
      // Heuristic 404 detection: upstream surfaces a 404 when the job has
      // expired or never existed. Without this check, every such error
      // would be reported as a 502 bad gateway.
      const status = result.error.message?.includes('404') ? 404 : 502;
      res.status(status).json({ error: result.error });
      return;
    }
    res.json(result.value);
  });

  // GET /api/code-indexer/search/structural?q=&limit= — Cypher search.
  router.get('/search/structural', async (req: Request, res: Response) => {
    const { q, limit, repo } = req.query as { q?: string; limit?: string; repo?: string };
    if (!q) {
      res.status(400).json({ error: 'q is required' });
      return;
    }
    const result = await structuralSearch(q, limit ? parseInt(limit, 10) : 20, repo ?? null);
    if (!result.ok) {
      res.status(502).json({ error: result.error });
      return;
    }
    res.json(result.value);
  });

  // GET /api/code-indexer/search/semantic?q=&k=&repo= — vector similarity search.
  router.get('/search/semantic', async (req: Request, res: Response) => {
    const { q, k, repo } = req.query as { q?: string; k?: string; repo?: string };
    if (!q) {
      res.status(400).json({ error: 'q is required' });
      return;
    }
    const result = await semanticSearch(q, k ? parseInt(k, 10) : 10, repo ?? null);
    if (!result.ok) {
      res.status(502).json({ error: result.error });
      return;
    }
    res.json(result.value);
  });

  // GET /api/code-indexer/search/symbol?fqn=&repo= — qualified-name lookup.
  router.get('/search/symbol', async (req: Request, res: Response) => {
    const { fqn, repo } = req.query as { fqn?: string; repo?: string };
    if (!fqn) {
      res.status(400).json({ error: 'fqn is required' });
      return;
    }
    const result = await symbolLookup(fqn, repo ?? null);
    if (!result.ok) {
      // Same 404 heuristic as the job status endpoint — treat "symbol not
      // found" as a proper Not Found rather than a gateway error.
      const status = result.error.message?.includes('404') ? 404 : 502;
      res.status(status).json({ error: result.error });
      return;
    }
    res.json(result.value);
  });

  // POST /api/code-indexer/context-bundle — build a grounded dev-agent
  // context bundle.
  router.post('/context-bundle', async (req: Request, res: Response) => {
    const { repo_path, task_description, k, depth } = req.body as {
      repo_path?: string;
      task_description?: string;
      k?: number;
      depth?: number;
    };
    if (!repo_path || !task_description) {
      res.status(400).json({ error: 'repo_path and task_description are required' });
      return;
    }
    const result = await buildContextBundle(repo_path, task_description, k ?? 10, depth ?? 2);
    if (!result.ok) {
      res.status(502).json({ error: result.error });
      return;
    }
    res.json(result.value);
  });

  // GET /api/code-indexer/github/repos?q=&limit= — list repos the upstream
  // service's GITHUB_TOKEN can see.  Used by the IndexPanel GitHub picker.
  router.get('/github/repos', async (req: Request, res: Response) => {
    const { q, limit } = req.query as { q?: string; limit?: string };
    const result = await listGithubRepos(q, limit ? parseInt(limit, 10) : 100);
    if (!result.ok) {
      // 401 errors from upstream mean the token is missing/invalid — surface
      // that through so the UI can prompt the user to set GITHUB_TOKEN.
      const status = result.error.message?.includes('401') ? 401 : 502;
      res.status(status).json({ error: result.error });
      return;
    }
    res.json(result.value);
  });

  // GET /api/code-indexer/search/files — paginated file listing with filter.
  router.get('/search/files', async (req: Request, res: Response) => {
    const { repo, filter, extension, limit, offset } = req.query as {
      repo?: string;
      filter?: string;
      extension?: string;
      limit?: string;
      offset?: string;
    };
    const result = await listFiles(
      repo ?? null,
      filter ?? '',
      extension ?? '',
      limit ? parseInt(limit, 10) : 500,
      offset ? parseInt(offset, 10) : 0,
    );
    if (!result.ok) {
      const status = result.error.message?.includes('404') ? 404 : 502;
      res.status(status).json({ error: result.error });
      return;
    }
    res.json(result.value);
  });

  // GET /api/code-indexer/search/types — node-label inventory for Browse tabs.
  router.get('/search/types', async (req: Request, res: Response) => {
    const { repo, non_zero_only } = req.query as { repo?: string; non_zero_only?: string };
    const nzo = non_zero_only === undefined ? true : non_zero_only !== 'false';
    const result = await listNodeTypes(repo ?? null, nzo);
    if (!result.ok) {
      const status = result.error.message?.includes('404') ? 404 : 502;
      res.status(status).json({ error: result.error });
      return;
    }
    res.json(result.value);
  });

  // GET /api/code-indexer/stats/:repo — per-repo graph breakdown.
  router.get('/stats/:repo', async (req: Request, res: Response) => {
    const repo = String(req.params['repo'] ?? '');
    if (!repo) {
      res.status(400).json({ error: 'repo is required' });
      return;
    }
    const result = await getRepoStats(repo);
    if (!result.ok) {
      const status = result.error.message?.includes('404') ? 404 : 502;
      res.status(status).json({ error: result.error });
      return;
    }
    res.json(result.value);
  });

  // DELETE /api/code-indexer/index/:repo — admin wipe of a repo's index files.
  router.delete('/index/:repo', async (req: Request, res: Response) => {
    const repo = String(req.params['repo'] ?? '');
    if (!repo) {
      res.status(400).json({ error: 'repo is required' });
      return;
    }
    const result = await deleteIndex(repo);
    if (!result.ok) {
      const status = result.error.message?.includes('404') ? 404 : 502;
      res.status(status).json({ error: result.error });
      return;
    }
    res.json(result.value);
  });

  // GET /api/code-indexer/index/jobs — list job history for the UI.
  router.get('/index/jobs', async (req: Request, res: Response) => {
    const { status, repo, limit } = req.query as {
      status?: string;
      repo?: string;
      limit?: string;
    };
    const result = await listJobs(status, repo, limit ? parseInt(limit, 10) : 50);
    if (!result.ok) {
      res.status(502).json({ error: result.error });
      return;
    }
    res.json(result.value);
  });

  // POST /api/code-indexer/index/jobs/clear — drop terminal job records.
  router.post('/index/jobs/clear', async (req: Request, res: Response) => {
    const status = (req.query['status'] as string | undefined) ?? 'done,failed';
    const result = await clearJobs(status);
    if (!result.ok) {
      res.status(502).json({ error: result.error });
      return;
    }
    res.json(result.value);
  });

  // DELETE /api/code-indexer/index/jobs/:jobId — drop a single terminal job.
  router.delete('/index/jobs/:jobId', async (req: Request, res: Response) => {
    const jobId = String(req.params['jobId'] ?? '');
    if (!jobId) {
      res.status(400).json({ error: 'jobId is required' });
      return;
    }
    const result = await deleteJob(jobId);
    if (!result.ok) {
      const msg = result.error.message ?? '';
      let status = 502;
      if (msg.includes('404')) status = 404;
      else if (msg.includes('409')) status = 409;
      res.status(status).json({ error: result.error });
      return;
    }
    res.json(result.value);
  });

  // GET /api/code-indexer/github/status — readiness badge (token + user + rate).
  router.get('/github/status', async (_req: Request, res: Response) => {
    const result = await getGithubStatus();
    if (!result.ok) {
      res.status(502).json({ error: result.error });
      return;
    }
    res.json(result.value);
  });

  // POST /api/code-indexer/github/index — clone + index a GitHub repo.
  // Returns the same shape as /index so the UI can reuse its polling flow.
  router.post('/github/index', async (req: Request, res: Response) => {
    const { full_name, branch, force_reindex } = req.body as {
      full_name?: string;
      branch?: string | null;
      force_reindex?: boolean;
    };
    if (!full_name) {
      res.status(400).json({ error: 'full_name is required (format: owner/repo)' });
      return;
    }
    const result = await indexGithubRepo(full_name, branch ?? null, force_reindex ?? false);
    if (!result.ok) {
      res.status(502).json({ error: result.error });
      return;
    }
    res.status(202).json(result.value);
  });

  return router;
}

export function authHeaders(useAlternate = false): Record<string, string> {
  if (!TOKEN) return {};
  if (useAlternate) {
    return { 'X-Forge-Service-Token': TOKEN };
  }
  return { Authorization: `Bearer ${TOKEN}` };
}

async function _get<T>(path: string): Promise<Result<T, ErrorEnvelope>> {
  try {
    const res = await fetch(`${BASE_URL}${path}`, {
      headers: { ...authHeaders() },
    });
    if (!res.ok) {
      const text = await res.text().catch(() => res.statusText);
      return Err(createErrorEnvelope('skill_api_http_error', `${res.status} ${text}`));
    }
    return Ok((await res.json()) as T);
  } catch (err) {
    return Err(createErrorEnvelope('skill_api_fetch_failed', err instanceof Error ? err.message : String(err)));
  }
}

