export function createSkillApiRouter(): Router {
  const router = createRouter();

  // GET /api/skill-api/health — liveness probe pass-through.
  router.get('/health', async (_req: Request, res: Response) => {
    const result = await checkHealth();
    if (!result.ok) {
      res.status(503).json({ error: result.error });
      return;
    }
    res.json(result.value);
  });

  // POST /api/skill-api/compose — composition engine (primary orchestration path).
  //
  // Phase filtering note: include the SDD phase in `domain_tags`, not just
  // `sdd_phase`. The Skill API uses domain_tags on Skill nodes for retrieval.
  router.post('/compose', async (req: Request, res: Response) => {
    const { task_description, sdd_phase, domain_tags, k } = req.body as {
      task_description?: string;
      sdd_phase?:        string;
      domain_tags?:      string[];
      k?:                number;
    };

    if (!task_description) {
      res.status(400).json({ error: 'task_description is required' });
      return;
    }
    if (!sdd_phase) {
      res.status(400).json({ error: 'sdd_phase is required' });
      return;
    }

    const result = await compose({ task_description, sdd_phase, domain_tags, k });
    if (!result.ok) {
      res.status(502).json({ error: result.error });
      return;
    }
    res.json(result.value);
  });

  // GET /api/skill-api/skills/search?q=&phase=&k= — direct retrieval by search.
  // Must come before /skills/:id to avoid route shadowing.
  router.get('/skills/search', async (req: Request, res: Response) => {
    const { q, phase, k } = req.query as { q?: string; phase?: string; k?: string };
    if (!q) {
      res.status(400).json({ error: 'q is required' });
      return;
    }
    if (!phase) {
      res.status(400).json({ error: 'phase is required' });
      return;
    }
    const result = await retrieveBySearch(q, phase, k ? parseInt(k, 10) : 5);
    if (!result.ok) {
      res.status(502).json({ error: result.error });
      return;
    }
    res.json(result.value);
  });

  // GET /api/skill-api/skills — catalogue with optional filters.
  // Query params: skill_class, category, domain_tag, limit, offset.
  router.get('/skills', async (req: Request, res: Response) => {
    const { skill_class, category, domain_tag, limit, offset } = req.query as {
      skill_class?: string;
      category?:   string;
      domain_tag?: string;
      limit?:      string;
      offset?:     string;
    };

    const filters: SkillListFilters = {};
    if (skill_class === 'domain' || skill_class === 'system') {
      filters.skill_class = skill_class as SkillClass;
    }
    if (category)   filters.category   = category;
    if (domain_tag) filters.domain_tag = domain_tag;
    if (limit)      filters.limit      = parseInt(limit, 10);
    if (offset)     filters.offset     = parseInt(offset, 10);

    const result = await listSkills(filters);
    if (!result.ok) {
      res.status(502).json({ error: result.error });
      return;
    }
    res.json(result.value);
  });

  // GET /api/skill-api/skills/:skillId/versions — version history.
  router.get('/skills/:skillId/versions', async (req: Request, res: Response) => {
    const skillId = String(req.params['skillId'] ?? '');
    const result = await getSkillVersions(skillId);
    if (!result.ok) {
      const status = result.error.message?.includes('404') ? 404 : 502;
      res.status(status).json({ error: result.error });
      return;
    }
    res.json(result.value);
  });

  // GET /api/skill-api/skills/:skillId — retrieve a single skill by ID.
  router.get('/skills/:skillId', async (req: Request, res: Response) => {
    const skillId = String(req.params['skillId'] ?? '');
    const result = await retrieve(skillId);
    if (!result.ok) {
      const status = result.error.error === 'skill_api_skill_not_found' ? 404 : 502;
      res.status(status).json({ error: result.error });
      return;
    }
    res.json(result.value);
  });

  // POST /api/skill-api/skills — ingest a new skill draft.
  router.post('/skills', async (req: Request, res: Response) => {
    const { prose, category, skill_class, domain_tags } = req.body as {
      prose?:       string;
      category?:    string;
      skill_class?: string;
      domain_tags?: string[];
    };

    if (!prose) {
      res.status(400).json({ error: 'prose is required' });
      return;
    }
    if (!category) {
      res.status(400).json({ error: 'category is required' });
      return;
    }
    if (skill_class !== 'domain' && skill_class !== 'system') {
      res.status(400).json({ error: 'skill_class must be "domain" or "system"' });
      return;
    }

    const result = await ingestSkill(prose, category, skill_class, domain_tags ?? []);
    if (!result.ok) {
      res.status(502).json({ error: result.error });
      return;
    }
    res.status(201).json(result.value);
  });

  // POST /api/skill-api/skills/:skillId/promote — promote latest draft to active.
  router.post('/skills/:skillId/promote', async (req: Request, res: Response) => {
    const skillId = String(req.params['skillId'] ?? '');
    const { promoted_by, change_summary } = req.body as {
      promoted_by?:    string;
      change_summary?: string;
    };

    if (!promoted_by) {
      res.status(400).json({ error: 'promoted_by is required' });
      return;
    }

    const result = await promoteSkill(skillId, promoted_by, change_summary);
    if (!result.ok) {
      const status = result.error.error === 'skill_api_skill_not_found' ? 404 : 502;
      res.status(status).json({ error: result.error });
      return;
    }
    res.json(result.value);
  });

  // GET /api/skill-api/telemetry/compositions/:compositionId — trace lookup (Phase 9).
  router.get('/telemetry/compositions/:compositionId', async (req: Request, res: Response) => {
    const compositionId = String(req.params['compositionId'] ?? '');
    const result = await getComposition(compositionId);
    if (!result.ok) {
      const status = result.error.error === 'skill_api_skill_not_found' ? 404 : 502;
      res.status(status).json({ error: result.error });
      return;
    }
    res.json(result.value);
  });

  return router;
}

export function authHeaders(useAlternate = false): Record<string, string> {
  if (!TOKEN) return {};
  if (useAlternate) {
    return { 'X-Forge-Service-Token': TOKEN };
  }
  return { Authorization: `Bearer ${TOKEN}` };
}

