function calculateSeparationScore(
  files: FileInfo[],
  violations: ViolationReport[]
): number {
  let score = 100;

  for (const violation of violations) {
    switch (violation.severity) {
      case "critical": score -= 10; break;
      case "high":     score -= 5;  break;
      case "medium":   score -= 3;  break;
      case "low":      score -= 1;  break;
    }
  }

  const fileCountFactor = Math.max(1, files.length / 100);
  score = score + (100 - score) * (1 - 1 / fileCountFactor) * 0.3;

  return Math.max(0, score);
}

function calculateCategoryScore(violationCount: number, threshold: number): number {
  if (violationCount === 0) return 100;
  return Math.max(0, 100 * Math.exp(-violationCount / threshold));
}

export function calculateComplianceScore(violations: {
  resultPattern: ResultPatternViolation[];
  errorEnvelopes: ErrorEnvelopeViolation[];
  specFirst: SpecFirstViolation[];
  structure: StructureViolation[];
  apiCompliance: APIComplianceReport[];
  database: DatabaseViolation[];
  makefile: MakefileReport;
}): Result<ComplianceScore, ErrorEnvelope> {
  try {
    const resultPatternScore = calculateCategoryScore(violations.resultPattern.length, 10);
    const errorEnvelopeScore = calculateCategoryScore(violations.errorEnvelopes.length, 5);
    const specFirstScore = calculateCategoryScore(violations.specFirst.length, 20);
    const structureScore = calculateCategoryScore(violations.structure.length, 5);
    const apiScore = calculateCategoryScore(violations.apiCompliance.length, 10);
    const databaseScore = calculateCategoryScore(violations.database.length, 5);
    const makefileScore = violations.makefile.exists
      ? calculateCategoryScore(violations.makefile.missingTargets.length, 4)
      : 0;

    const weights = {
      resultPattern: 0.25,
      errorEnvelope: 0.10,
      specFirst: 0.25,
      structure: 0.15,
      api: 0.10,
      database: 0.10,
      makefile: 0.05,
    };

    const overall =
      resultPatternScore * weights.resultPattern +
      errorEnvelopeScore * weights.errorEnvelope +
      specFirstScore * weights.specFirst +
      structureScore * weights.structure +
      apiScore * weights.api +
      databaseScore * weights.database +
      makefileScore * weights.makefile;

    return Ok({
      overall: Math.round(overall),
      specFirst: Math.round(specFirstScore),
      resultPattern: Math.round(resultPatternScore),
      projectStructure: Math.round(structureScore),
      apiStandards: Math.round(apiScore),
      databaseStandards: Math.round(databaseScore),
      makefileStandards: Math.round(makefileScore),
    });
  } catch (error) {
    return Err(
      createErrorEnvelope(
        "calculation_error",
        `Failed to calculate compliance score: ${error instanceof Error ? error.message : String(error)}`
      )
    );
  }
}

export function getPrismaClient(): PrismaClient {
  if (singleton) return singleton;

  if (!process.env['FORGE_DATABASE_URL']) {
    process.env['FORGE_DATABASE_URL'] = DEFAULT_URL;
  }

  singleton = new PrismaClient({
    log: process.env['NODE_ENV'] === 'production' ? ['error'] : ['error', 'warn'],
  });

  // SQLite performance + concurrency tuning. Use $queryRawUnsafe for all
  // PRAGMAs — Prisma is conservative about whether a raw statement returns
  // rows and rejects $executeRawUnsafe when any result is produced.
  // Fire-and-forget; real errors surface on the first real query.
  void singleton.$queryRawUnsafe('PRAGMA journal_mode=WAL;').catch(() => {});
  void singleton.$queryRawUnsafe('PRAGMA busy_timeout=5000;').catch(() => {});
  void singleton.$queryRawUnsafe('PRAGMA synchronous=NORMAL;').catch(() => {});
  void singleton.$queryRawUnsafe('PRAGMA foreign_keys=ON;').catch(() => {});

  return singleton;
}

async detectDriftAgainst(targetRef: string, latestDate?: string): Promise<Result<DriftReport, ErrorEnvelope>> {
  // Read lockfile
  const lockfileResult = readLockfile(this.root);
  if (!lockfileResult.ok) return Err(lockfileResult.error);

  const lockfile = lockfileResult.value;

  // Extract source repository from global specs
  if (lockfile.global_specs.length === 0) {
    return Err(
      createErrorEnvelope(
        "drift_no_global_specs",
        "No global specs found in spec.lock. Nothing to check for drift.",
      ),
    );
  }

  const firstSpec = lockfile.global_specs[0];
  if (!firstSpec) {
    return Err(
      createErrorEnvelope(
        "drift_no_global_specs",
        "No global specs found in spec.lock. Nothing to check for drift.",
      ),
    );
  }

  const currentRef = firstSpec.ref;
  const currentCommitSha = firstSpec.commit_sha;

  // Use provided date or current time
  const targetDate = latestDate || new Date().toISOString();
  const daysBehind = calculateDaysBehind(lockfile.generated, targetDate);

  // Compare versions
  const versionDiff: VersionDiff = {
    currentRef,
    currentCommitSha,
    latestRef: targetRef,
    latestPublishedAt: targetDate,
    daysBehind,
    affectedSpecs: lockfile.global_specs.map((s) => s.path),
  };

  // Classify severity
  const severity = classifySeverity(versionDiff.daysBehind, currentRef, targetRef);

  // Build report
  const report: DriftReport = {
    projectName: this.root.split("/").pop() || "unknown",
    currentRef,
    latestRef: targetRef,
    daysBehind,
    severity,
    affectedSpecs: versionDiff.affectedSpecs,
    recommendation: currentRef === targetRef
      ? "Your project is up to date."
      : `Your project is behind ${targetRef}.`,
  };

  return Ok(report);
}

function calculateDaysBehind(lockedDate: string, latestDate: string): number {
  try {
    const locked = new Date(lockedDate);
    const latest = new Date(latestDate);
    const diffMs = latest.getTime() - locked.getTime();
    const diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24));
    return Math.max(0, diffDays);
  } catch {
    return 0;
  }
}

function classifySeverity(daysBehind: number, currentRef: string, latestRef: string): DriftSeverity {
  // Parse semantic versions if possible
  const currentVersion = parseSemanticVersion(currentRef);
  const latestVersion = parseSemanticVersion(latestRef);

  if (currentVersion && latestVersion) {
    // Major version change = critical
    if (latestVersion.major > currentVersion.major) {
      return "critical";
    }
    // Minor version change = major
    if (latestVersion.minor > currentVersion.minor) {
      return "major";
    }
  }

  // Fall back to time-based classification (or if versions match but time is old)
  if (daysBehind >= 90) {
    return "critical";
  }
  if (daysBehind >= 30) {
    return "major";
  }
  return "minor";
}

function parseSemanticVersion(ref: string): { major: number; minor: number; patch: number } | null {
  const match = ref.match(/^v?(\d+)\.(\d+)\.(\d+)/);
  if (!match || !match[1] || !match[2] || !match[3]) return null;

  return {
    major: parseInt(match[1], 10),
    minor: parseInt(match[2], 10),
    patch: parseInt(match[3], 10),
  };
}

function readLockfile(root: string): Result<Lockfile, ErrorEnvelope> {
  const lockPath = join(root, ".specs", "spec.lock");

  if (!existsSync(lockPath)) {
    return Err(
      createErrorEnvelope(
        "drift_no_lockfile",
        `No spec.lock found at ${lockPath}. Run 'forge sync' first to generate the lockfile.`,
        {
          guidance: ["Run: forge sync"],
        },
      ),
    );
  }

  try {
    const raw = readFileSync(lockPath, "utf-8");
    const parsed = parseYaml(raw) as Lockfile;

    if (!parsed.version || !parsed.generated || !Array.isArray(parsed.global_specs)) {
      return Err(
        createErrorEnvelope(
          "drift_invalid_lockfile",
          `Invalid spec.lock format at ${lockPath}. Expected version, generated, and global_specs fields.`,
        ),
      );
    }

    return Ok(parsed);
  } catch (error) {
    return Err(
      createErrorEnvelope(
        "drift_lockfile_read_failed",
        `Failed to read or parse spec.lock at ${lockPath}: ${String(error)}`,
      ),
    );
  }
}

export function getErrorGuidance(
  errorCode: string,
  context: ErrorContext = {},
): ErrorGuidance {
  // Use Object.prototype.hasOwnProperty to avoid prototype pollution issues
  const guidance = Object.prototype.hasOwnProperty.call(ERROR_GUIDANCE_CATALOG, errorCode)
    ? ERROR_GUIDANCE_CATALOG[errorCode]
    : undefined;

  if (!guidance) {
    return {
      suggestions: ["Check the error message for details", "Run 'forge doctor' to diagnose common issues"],
      exampleCommands: ["forge doctor", "forge --help"],
      documentationLinks: ["https://github.com/navistone/engineering-agent-standards"],
    };
  }

  // Replace context placeholders in suggestions and commands
  const suggestions = guidance.suggestions.map(s => replaceContextPlaceholders(s, context));
  const exampleCommands = guidance.exampleCommands.map(c => replaceContextPlaceholders(c, context));

  return {
    suggestions,
    exampleCommands,
    documentationLinks: guidance.documentationLinks,
  };
}

function replaceContextPlaceholders(text: string, context: ErrorContext): string {
  return text.replace(/\{(\w+)\}/g, (match, key) => {
    const value = context[key];
    return value !== undefined ? String(value) : match;
  });
}

export function createErrorEnvelope(
  error: string,
  message: string,
  details?: Record<string, unknown>,
): ErrorEnvelope {
  // Extract context for error guidance from details
  const context: Record<string, string | number | boolean | undefined> = {};
  if (details) {
    for (const [key, value] of Object.entries(details)) {
      if (typeof value === "string" || typeof value === "number" || typeof value === "boolean") {
        context[key] = value;
      }
    }
  }

  // Get error recovery guidance
  const guidance = getErrorGuidance(error, context);

  // Merge guidance into details
  const enhancedDetails = {
    ...details,
    guidance: {
      suggestions: guidance.suggestions,
      exampleCommands: guidance.exampleCommands,
      documentationLinks: guidance.documentationLinks,
    },
  };

  return {
    error,
    message,
    timestamp: new Date().toISOString(),
    traceId: generateTraceId(),
    details: enhancedDetails,
  };
}

export function generateTraceId(): string {
  return uuidv4();
}

async call(
  toolName: string,
  args: Record<string, unknown>,
): Promise<Result<MCPToolResult, ErrorEnvelope>> {
  if (!this.process) {
    return Err(createErrorEnvelope('github_mcp_not_connected', 'GitHub MCP client is not connected'));
  }

  try {
    const result = await this.sendRequest('tools/call', {
      name: toolName,
      arguments: args,
    });

    return Ok(result as MCPToolResult);
  } catch (error) {
    return Err(createErrorEnvelope(
      'github_mcp_call_failed',
      `GitHub MCP tool call failed: ${error instanceof Error ? error.message : String(error)}`,
    ));
  }
}

function checkGateSequencing(events: AuditEvent[]): ComplianceCheck {
  const approvals = events
    .filter(e => e.type === 'gate_approved' && typeof e.gate === 'string')
    .sort((a, b) => a.timestamp.localeCompare(b.timestamp));

  if (approvals.length === 0) {
    return {
      id:      'gate_sequencing',
      name:    'Gate sequence',
      status:  'na',
      message: 'No gates approved on this task yet.',
    };
  }

  if (approvals.length < 2) {
    // A single approval can't be "out of order" — insufficient signal.
    return {
      id:      'gate_sequencing',
      name:    'Gate sequence',
      status:  'pass',
      message: `Single gate approval (${approvals[0]?.gate}) — no ordering to check.`,
    };
  }

  const outOfOrder: AuditEvent[] = [];
  for (let i = 1; i < approvals.length; i++) {
    const prev = gateRank(approvals[i - 1]?.gate);
    const curr = gateRank(approvals[i]?.gate);
    if (prev >= 0 && curr >= 0 && curr < prev) {
      const approval = approvals[i];
      if (approval) outOfOrder.push(approval);
    }
  }

  if (outOfOrder.length === 0) {
    const seq = approvals.map(a => a.gate).join(' → ');
    return {
      id:      'gate_sequencing',
      name:    'Gate sequence',
      status:  'pass',
      message: `Approvals followed canonical order: ${seq}.`,
    };
  }

  return {
    id:      'gate_sequencing',
    name:    'Gate sequence',
    status:  'warn',
    message: `${outOfOrder.length} approval${outOfOrder.length === 1 ? '' : 's'} out of canonical order (pm → arch_pm → arch).`,
    evidence: outOfOrder.map(e => e.id),
  };
}

function checkGroundedTurns(events: AuditEvent[]): ComplianceCheck {
  const completed = events.filter(e => e.type === 'chat.turn.completed');

  if (completed.length === 0) {
    return {
      id:      'grounded_turns',
      name:    'Orchestrated turns',
      status:  'na',
      message: 'No orchestrator turns recorded on this task yet.',
    };
  }

  const ungrounded = completed.filter(e => {
    const cid = (e.payload as Record<string, unknown>)['compositionId'];
    return typeof cid !== 'string' || cid.length === 0;
  });

  if (ungrounded.length === 0) {
    return {
      id:      'grounded_turns',
      name:    'Orchestrated turns',
      status:  'pass',
      message: `All ${completed.length} turn${completed.length === 1 ? '' : 's'} recorded a composition_id.`,
    };
  }

  return {
    id:      'grounded_turns',
    name:    'Orchestrated turns',
    status:  'fail',
    message: `${ungrounded.length} / ${completed.length} turn${completed.length === 1 ? '' : 's'} missing composition_id — LLM call bypassed the orchestrator.`,
    evidence: ungrounded.map(e => e.id),
  };
}

function checkSpecBeforeDev(events: AuditEvent[]): ComplianceCheck {
  const sorted = [...events].sort((a, b) => a.timestamp.localeCompare(b.timestamp));
  const firstDevTransition = sorted.find(
    e => e.type === 'stage_changed' && e.newValue === 'development',
  );

  if (!firstDevTransition) {
    return {
      id:      'spec_before_dev',
      name:    'Spec before dev',
      status:  'na',
      message: 'Task has not reached development stage yet.',
    };
  }

  const specBefore = sorted.find(
    e => e.type === 'spec_generated' && e.timestamp <= firstDevTransition.timestamp,
  );

  if (specBefore) {
    return {
      id:      'spec_before_dev',
      name:    'Spec before dev',
      status:  'pass',
      message: 'Spec generated before entering development.',
      evidence: [specBefore.id, firstDevTransition.id],
    };
  }

  return {
    id:      'spec_before_dev',
    name:    'Spec before dev',
    status:  'fail',
    message: 'Task reached development without a spec_generated event — workflow short-circuit.',
    evidence: [firstDevTransition.id],
  };
}

export function classifyTaskCompliance(
  taskId: string,
  events: AuditEvent[],
): TaskCompliance {
  const checks = [
    checkGroundedTurns(events),
    checkGateSequencing(events),
    checkSpecBeforeDev(events),
  ];

  const lastActivity = events.length > 0
    ? events.reduce((latest, e) => (e.timestamp > latest ? e.timestamp : latest), events[0]?.timestamp ?? '')
    : null;

  const allPassed = checks.every(c => c.status === 'pass' || c.status === 'na');

  return {
    taskId,
    lastActivity: lastActivity || null,
    checks,
    allPassed,
  };
}

function gateRank(gate: string | undefined): number {
  if (!gate) return -1;
  return (GATE_ORDER as readonly string[]).indexOf(gate);
}

export function Err<E>(error: E): Result<never, E> {
  return { ok: false, error };
}

export function Ok<T>(value: T): Result<T, never> {
  return { ok: true, value };
}

export function map<T, U, E>(
  result: Result<T, E>,
  fn: (value: T) => U,
): Result<U, E> {
  return result.ok ? Ok(fn(result.value)) : result;
}

export function createGovernanceRouter(): IRouter {
  const router = Router();

  router.get('/compliance', async (req: Request, res: Response) => {
    const limitRaw = typeof req.query['limit'] === 'string' ? req.query['limit'] : '20';
    const limit = Math.max(1, Math.min(100, Number(limitRaw) || 20));

    try {
      const prisma = getPrismaClient();

      // Find the most-recently-active task IDs by latest audit timestamp.
      const recent = await prisma.auditEvent.findMany({
        where:   { type: { in: AUDIT_TYPES_CONSUMED as unknown as string[] } },
        select:  { taskId: true, timestamp: true },
        orderBy: { timestamp: 'desc' },
        take:    limit * 20, // over-fetch; dedupe below
      });

      const seen = new Set<string>();
      const taskIds: string[] = [];
      for (const row of recent) {
        if (seen.has(row.taskId)) continue;
        seen.add(row.taskId);
        taskIds.push(row.taskId);
        if (taskIds.length >= limit) break;
      }

      if (taskIds.length === 0) {
        res.json({ results: [] as TaskCompliance[] });
        return;
      }

      // Pull the full event stream for each (scoped to the heuristic's
      // consumed types for efficiency).
      const events = await prisma.auditEvent.findMany({
        where: {
          taskId: { in: taskIds },
          type:   { in: AUDIT_TYPES_CONSUMED as unknown as string[] },
        },
        orderBy: { timestamp: 'asc' },
      }) as PrismaAuditRow[];

      // Group by taskId
      const byTask = new Map<string, AuditEvent[]>();
      for (const row of events) {
        const list = byTask.get(row.taskId) ?? [];
        list.push(rowToEvent(row));
        byTask.set(row.taskId, list);
      }

      const results: TaskCompliance[] = taskIds.map(id =>
        classifyTaskCompliance(id, byTask.get(id) ?? []),
      );

      res.json({ results });
    } catch (err) {
      res.status(500).json({
        error: createErrorEnvelope(
          'governance_compliance_failed',
          err instanceof Error ? err.message : String(err),
        ),
      });
    }
  });

  router.use((_req: Request, res: Response) => {
    res.status(404).json({
      error: createErrorEnvelope(
        'governance_route_not_found',
        'Unknown /api/governance/* route.',
      ),
    });
  });

  return router;
}

function rowToEvent(r: PrismaAuditRow): AuditEvent {
  let payload: Record<string, unknown> = {};
  try { payload = JSON.parse(r.payload) as Record<string, unknown>; } catch { /* ignore */ }

  return {
    id:            r.id,
    taskId:        r.taskId,
    type:          r.type as AuditEvent['type'],
    actorId:       r.actorId,
    actorRole:     r.actorRole ?? undefined,
    timestamp:     r.timestamp.toISOString(),
    summary:       r.summary,
    payload,
    previousValue: r.previousValue ?? undefined,
    newValue:      r.newValue ?? undefined,
    gate:          (r.gate ?? undefined) as AuditEvent['gate'],
    stage:         (r.stage ?? undefined) as AuditEvent['stage'],
  };
}

