def _build_assignment_arrow_function_qualified_name(
    self,
    member_expr: ASTNode,
    _arrow_function: ASTNode,
    module_qn: str,
    function_name: str,
    lang_config: LanguageSpec,
) -> str | None:
    current = member_expr.parent
    if current and current.type == cs.TS_ASSIGNMENT_EXPRESSION:
        current = current.parent

    skip_types = (cs.TS_EXPRESSION_STATEMENT, cs.TS_STATEMENT_BLOCK)
    path_parts = self._js_collect_ancestor_path_parts(
        current, lang_config, skip_types
    )
    return self._js_format_qualified_name(module_qn, path_parts, function_name)

def _process_direct_arrow_functions(
    self,
    method_names: list[ASTNode],
    arrow_functions: list[ASTNode],
    module_qn: str,
    lang_config,
) -> None:
    for method_name, arrow_function in zip(method_names, arrow_functions):
        if not method_name.text or not arrow_function:
            continue

        function_name = safe_decode_text(method_name)
        if not function_name:
            continue

        function_qn = self._resolve_direct_arrow_qn(
            method_name, arrow_function, module_qn, function_name, lang_config
        )

        self._register_arrow_function(
            function_name, function_qn, arrow_function, lg.JS_OBJECT_ARROW_FOUND
        )

def _process_member_expr_functions(
    self,
    member_exprs: list[ASTNode],
    function_nodes: list[ASTNode],
    module_qn: str,
    lang_config,
    log_message: str,
) -> None:
    for member_expr, function_node in zip(member_exprs, function_nodes):
        if not member_expr.text or not function_node:
            continue

        member_text = safe_decode_with_fallback(member_expr)
        if cs.SEPARATOR_DOT not in member_text:
            continue

        function_name = member_text.split(cs.SEPARATOR_DOT)[-1]
        function_qn = self._resolve_member_expr_qn(
            member_expr, function_node, module_qn, function_name, lang_config
        )

        self._register_arrow_function(
            function_name, function_qn, function_node, log_message
        )

def _resolve_direct_arrow_qn(
    self,
    method_name_node: ASTNode,
    _arrow_function: ASTNode,
    module_qn: str,
    function_name: str,
    lang_config,
) -> str:
    if lang_config:
        function_qn = self._build_object_arrow_qualified_name(
            method_name_node, module_qn, function_name, lang_config
        )
        if function_qn is not None:
            return function_qn
    return f"{module_qn}{cs.SEPARATOR_DOT}{function_name}"

def _resolve_member_expr_qn(
    self,
    member_expr: ASTNode,
    function_node: ASTNode,
    module_qn: str,
    function_name: str,
    lang_config,
) -> str:
    if lang_config:
        function_qn = self._build_assignment_arrow_function_qualified_name(
            member_expr, function_node, module_qn, function_name, lang_config
        )
        if function_qn is not None:
            return function_qn
    return f"{module_qn}{cs.SEPARATOR_DOT}{function_name}"

def safe_decode_text(node: ASTNode | TreeSitterNodeProtocol | None) -> str | None:
    if node is None or (text_bytes := node.text) is None:
        return None
    if isinstance(text_bytes, bytes):
        return _cached_decode_bytes(text_bytes)
    return str(text_bytes)

def _execute_query(
    self,
    query: str,
    params: dict[str, PropertyValue] | None = None,
) -> list[ResultRow]:
    if not self.conn:
        raise ConnectionError(ex.CONN)
    params = params or {}
    try:
        result = self.conn.execute(query, params)
        return _result_to_rows(result)
    except Exception as e:
        err_str = str(e).lower()
        if (
            ERR_SUBSTR_ALREADY_EXISTS not in err_str
            and ERR_SUBSTR_CONSTRAINT not in err_str
        ):
            logger.error(ls.MG_CYPHER_ERROR.format(error=e))
            logger.error(ls.MG_CYPHER_QUERY.format(query=query))
            logger.error(ls.MG_CYPHER_PARAMS.format(params=params))
        raise

def _l2_normalise(vec: list[float]) -> list[float]:
    """Return a unit-norm copy of ``vec``.

    Zero vectors are returned unchanged so callers don't have to special-case
    them; sqrt of a tiny float still produces a defined result.
    """
    mag = math.sqrt(sum(x * x for x in vec))
    if mag == 0.0:
        return list(vec)
    return [x / mag for x in vec]

def _import_pyarrow() -> Any:
    """Import and return the ``pyarrow`` module, raising RuntimeError when absent."""
    try:
        import pyarrow as pa  # type: ignore[import-not-found]
    except ImportError as exc:  # pragma: no cover — explicit operator guidance
        raise RuntimeError(
            "pyarrow is not installed. Install the optional dep with "
            "`pip install code-graph-rag[arrow]`."
        ) from exc
    return pa

def _normalise_matrix(rows: list[EmbeddingRow]) -> list[list[float]]:
    """L2-normalise each embedding; preserve zero vectors."""
    import numpy as np  # numpy is a hard dep of code-graph-rag

    mat = np.asarray(
        [r.embedding for r in rows], dtype=np.float32
    )  # (N, 768)
    norms = np.linalg.norm(mat, axis=1, keepdims=True)
    norms[norms == 0.0] = 1.0
    unit = mat / norms
    return unit.tolist()

