def process_all_method_overrides(
    function_registry: FunctionRegistryTrieProtocol,
    class_inheritance: dict[str, list[str]],
    ingestor: IngestorProtocol,
) -> None:
    logger.info(logs.CLASS_PASS_4)

    for method_qn in function_registry.keys():
        if (
            function_registry[method_qn] == NodeType.METHOD
            and cs.SEPARATOR_DOT in method_qn
        ):
            parts = method_qn.rsplit(cs.SEPARATOR_DOT, 1)
            if len(parts) == 2:
                class_qn, method_name = parts
                check_method_overrides(
                    method_qn,
                    method_name,
                    class_qn,
                    function_registry,
                    class_inheritance,
                    ingestor,
                )

def _add_dependency(
    self, dep_name: str, dep_spec: str, properties: dict[str, str] | None = None
) -> None:
    if not dep_name or dep_name.lower() in cs.EXCLUDED_DEPENDENCY_NAMES:
        return

    logger.info(ls.DEF_FOUND_DEPENDENCY.format(name=dep_name, spec=dep_spec))
    self.ingestor.ensure_node_batch(
        cs.NodeLabel.EXTERNAL_PACKAGE, {cs.KEY_NAME: dep_name}
    )

    rel_properties = {cs.KEY_VERSION_SPEC: dep_spec} if dep_spec else {}
    if properties:
        rel_properties |= properties

    self.ingestor.ensure_relationship_batch(
        (cs.NodeLabel.PROJECT, cs.KEY_NAME, self.project_name),
        cs.RelationshipType.DEPENDS_ON_EXTERNAL,
        (cs.NodeLabel.EXTERNAL_PACKAGE, cs.KEY_NAME, dep_name),
        properties=rel_properties,
    )

def process_dependencies(self, filepath: Path) -> None:
    logger.info(ls.DEF_PARSING_DEPENDENCY.format(path=filepath))

    dependencies = parse_dependencies(filepath)
    for dep in dependencies:
        self._add_dependency(dep.name, dep.spec, dep.properties)

def parse(self, file_path: Path) -> list[Dependency]:
    dependencies: list[Dependency] = []
    try:
        tree = ET.parse(file_path)
        root = tree.getroot()

        for pkg_ref in root.iter(cs.DEP_XML_PACKAGE_REF):
            include = pkg_ref.get(cs.DEP_ATTR_INCLUDE)
            version = pkg_ref.get(cs.DEP_ATTR_VERSION)

            if include:
                dependencies.append(Dependency(include, version or ""))
    except Exception as e:
        logger.error(ls.DEP_PARSE_ERROR_CSPROJ.format(path=file_path, error=e))
    return dependencies

def parse_dependencies(file_path: Path) -> list[Dependency]:
    file_name = file_path.name.lower()

    match file_name:
        case cs.DEP_FILE_PYPROJECT:
            return PyProjectTomlParser().parse(file_path)
        case cs.DEP_FILE_REQUIREMENTS:
            return RequirementsTxtParser().parse(file_path)
        case cs.DEP_FILE_PACKAGE_JSON:
            return PackageJsonParser().parse(file_path)
        case cs.DEP_FILE_CARGO:
            return CargoTomlParser().parse(file_path)
        case cs.DEP_FILE_GOMOD:
            return GoModParser().parse(file_path)
        case cs.DEP_FILE_GEMFILE:
            return GemfileParser().parse(file_path)
        case cs.DEP_FILE_COMPOSER:
            return ComposerJsonParser().parse(file_path)
        case _ if file_path.suffix.lower() == cs.CSPROJ_SUFFIX:
            return CsprojParser().parse(file_path)
        case _:
            return []

def identify_structure(self) -> None:
    directories = {self.repo_path}
    for path in self.repo_path.rglob(cs.GLOB_ALL):
        if path.is_dir() and not should_skip_path(
            path,
            self.repo_path,
            exclude_paths=self.exclude_paths,
            unignore_paths=self.unignore_paths,
        ):
            directories.add(path)

    for root in sorted(directories):
        relative_root = root.relative_to(self.repo_path)

        parent_rel_path = relative_root.parent
        parent_container_qn = self.structural_elements.get(parent_rel_path)

        is_package = False
        package_indicators: set[str] = set()

        for lang_queries in self.queries.values():
            lang_config = lang_queries[cs.QUERY_CONFIG]
            package_indicators.update(lang_config.package_indicators)

        for indicator in package_indicators:
            if (root / indicator).exists():
                is_package = True
                break

        if is_package:
            package_qn = cs.SEPARATOR_DOT.join(
                [self.project_name] + list(relative_root.parts)
            )
            self.structural_elements[relative_root] = package_qn
            logger.info(
                logs.STRUCT_IDENTIFIED_PACKAGE.format(package_qn=package_qn)
            )
            self.ingestor.ensure_node_batch(
                cs.NodeLabel.PACKAGE,
                {
                    cs.KEY_QUALIFIED_NAME: package_qn,
                    cs.KEY_NAME: root.name,
                    cs.KEY_PATH: relative_root.as_posix(),
                },
            )
            parent_identifier = self._get_parent_identifier(
                parent_rel_path, parent_container_qn
            )
            self.ingestor.ensure_relationship_batch(
                parent_identifier,
                cs.RelationshipType.CONTAINS_PACKAGE,
                (cs.NodeLabel.PACKAGE, cs.KEY_QUALIFIED_NAME, package_qn),
            )
        elif root != self.repo_path:
            self.structural_elements[relative_root] = None
            logger.info(
                logs.STRUCT_IDENTIFIED_FOLDER.format(relative_root=relative_root)
            )
            self.ingestor.ensure_node_batch(
                cs.NodeLabel.FOLDER,
                {cs.KEY_PATH: relative_root.as_posix(), cs.KEY_NAME: root.name},
            )
            parent_identifier = self._get_parent_identifier(
                parent_rel_path, parent_container_qn
            )
            self.ingestor.ensure_relationship_batch(
                parent_identifier,
                cs.RelationshipType.CONTAINS_FOLDER,
                (cs.NodeLabel.FOLDER, cs.KEY_PATH, relative_root.as_posix()),
            )

