]:
    parsers: dict[cs.SupportedLanguage, Parser] = {}
    queries: dict[cs.SupportedLanguage, LanguageQueries] = {}
    available_languages: list[cs.SupportedLanguage] = []

    for lang_key, lang_config in deepcopy(LANGUAGE_SPECS).items():
