def _l2_normalise(vec: list[float]) -> list[float]:
    """Return a unit-norm copy of ``vec``.

    Zero vectors are returned unchanged so callers don't have to special-case
    them; sqrt of a tiny float still produces a defined result.
    """
    mag = math.sqrt(sum(x * x for x in vec))
    if mag == 0.0:
        return list(vec)
    return [x / mag for x in vec]

def _import_pyarrow() -> Any:
    """Import and return the ``pyarrow`` module, raising RuntimeError when absent."""
    try:
        import pyarrow as pa  # type: ignore[import-not-found]
    except ImportError as exc:  # pragma: no cover — explicit operator guidance
        raise RuntimeError(
            "pyarrow is not installed. Install the optional dep with "
            "`pip install code-graph-rag[arrow]`."
        ) from exc
    return pa

def _normalise_matrix(rows: list[EmbeddingRow]) -> list[list[float]]:
    """L2-normalise each embedding; preserve zero vectors."""
    import numpy as np  # numpy is a hard dep of code-graph-rag

    mat = np.asarray(
        [r.embedding for r in rows], dtype=np.float32
    )  # (N, 768)
    norms = np.linalg.norm(mat, axis=1, keepdims=True)
    norms[norms == 0.0] = 1.0
    unit = mat / norms
    return unit.tolist()

def _row(qn: str, idx: int) -> EmbeddingRow:
    """Build a synthetic EmbeddingRow with a unit vector at dimension ``idx``."""
    return EmbeddingRow(
        qualified_name=qn,
        embedding=_unit_vec(idx),
        file_path=f"/repo/{qn.split('.', maxsplit=1)[0]}.py",
        start_line=idx,
        end_line=idx + 5,
        symbol_type="Function",
    )

