        return _result_to_rows(result)
    except Exception as e:
        err_str = str(e).lower()
        if (
            ERR_SUBSTR_ALREADY_EXISTS not in err_str
            and ERR_SUBSTR_CONSTRAINT not in err_str
        ):
            logger.error(ls.MG_CYPHER_ERROR.format(error=e))
            logger.error(ls.MG_CYPHER_QUERY.format(query=query))
            logger.error(ls.MG_CYPHER_PARAMS.format(params=params))
        raise

def _clean_cypher_response(response_text: str) -> str:
    query = response_text.strip().replace(cs.CYPHER_BACKTICK, "")
    if query.startswith(cs.CYPHER_PREFIX):
        query = query[len(cs.CYPHER_PREFIX) :].strip()
    if not query.endswith(cs.CYPHER_SEMICOLON):
        query += cs.CYPHER_SEMICOLON
    return query

def _validate_cypher_read_only(query: str) -> None:
    upper_query = query.upper()
    for keyword, pattern in _CYPHER_DANGEROUS_PATTERNS:
        if pattern.search(upper_query):
            raise ex.LLMGenerationError(
                ex.LLM_DANGEROUS_QUERY.format(keyword=keyword, query=query)
            )

def create_query_tool(
    ingestor: QueryProtocol,
    cypher_gen: CypherGenerator,
    console: Console | None = None,
) -> Tool:
    if console is None:
        console = Console(width=None, stderr=True, force_terminal=True)

    async def query_codebase_knowledge_graph(
        natural_language_query: str,
    ) -> QueryGraphData:
        logger.info(ls.TOOL_QUERY_RECEIVED.format(query=natural_language_query))
        cypher_query = QUERY_NOT_AVAILABLE
        try:
            cypher_query = await cypher_gen.generate(natural_language_query)

            results = await asyncio.to_thread(ingestor.fetch_all, cypher_query)

            if results:
                table = Table(
                    show_header=True,
                    header_style="bold magenta",
                )
                headers = results[0].keys()
                for header in headers:
                    table.add_column(header)

                for row in results:
                    renderable_values = []
                    for value in row.values():
                        if value is None:
                            renderable_values.append("")
                        elif isinstance(value, bool):
                            renderable_values.append("✓" if value else "✗")
                        elif isinstance(value, int | float):
                            renderable_values.append(str(value))
                        else:
                            renderable_values.append(str(value))
                    table.add_row(*renderable_values)

                console.print(
                    Panel(
                        table,
                        title=QUERY_RESULTS_PANEL_TITLE,
                        expand=False,
                    )
                )

            summary = QUERY_SUMMARY_SUCCESS.format(count=len(results))
            return QueryGraphData(
                query_used=cypher_query, results=results, summary=summary
            )
        except ex.LLMGenerationError as e:
            return QueryGraphData(
                query_used=QUERY_NOT_AVAILABLE,
                results=[],
                summary=QUERY_SUMMARY_TRANSLATION_FAILED.format(error=e),
            )
        except Exception as e:
            logger.exception(ls.TOOL_QUERY_ERROR.format(error=e))
            return QueryGraphData(
                query_used=cypher_query,
                results=[],
                summary=QUERY_SUMMARY_DB_ERROR.format(error=e),
            )

    return Tool(
        function=query_codebase_knowledge_graph,
        name=td.AgenticToolName.QUERY_GRAPH,
        description=td.CODEBASE_QUERY,
    )

def analyze_graph(graph_file: str) -> None:
    logger.info(logs.GRAPH_ANALYZING.format(path=graph_file))

    try:
        _perform_graph_analysis(graph_file)
    except Exception as e:
        logger.error(logs.GRAPH_ANALYSIS_ERROR.format(error=e))
        sys.exit(1)

def log_example_nodes(graph: GraphLoader, node_label: str, limit: int = 5) -> None:
    nodes = graph.find_nodes_by_label(node_label)
    logger.info(logs.GRAPH_FOUND_NODES.format(count=len(nodes), label=node_label))

    if nodes:
        logger.info(logs.GRAPH_EXAMPLE_NAMES.format(label=node_label))
        for node in nodes[:limit]:
            name = node.properties.get(KEY_NAME, DEFAULT_NAME)
            logger.info(logs.GRAPH_EXAMPLE_NAME.format(name=name))
        if len(nodes) > limit:
            logger.info(logs.GRAPH_MORE_NODES.format(count=len(nodes) - limit))

def log_node_and_relationship_types(summary: GraphSummary) -> None:
    logger.info(logs.GRAPH_NODE_TYPES)
    for label, count in summary.get(KEY_NODE_LABELS, {}).items():
        logger.info(logs.GRAPH_NODE_COUNT.format(label=label, count=count))

    logger.info(logs.GRAPH_REL_TYPES)
    for rel_type, count in summary.get(KEY_RELATIONSHIP_TYPES, {}).items():
        logger.info(logs.GRAPH_REL_COUNT.format(rel_type=rel_type, count=count))

def log_summary(summary: GraphSummary) -> None:
    logger.info(logs.GRAPH_SUMMARY)
    logger.info(logs.GRAPH_TOTAL_NODES.format(count=summary.get(KEY_TOTAL_NODES, 0)))
    logger.info(
        logs.GRAPH_TOTAL_RELS.format(count=summary.get(KEY_TOTAL_RELATIONSHIPS, 0))
    )
    if KEY_METADATA in summary and KEY_EXPORTED_AT in summary[KEY_METADATA]:
        logger.info(
            logs.GRAPH_EXPORTED_AT.format(
                timestamp=summary[KEY_METADATA][KEY_EXPORTED_AT]
            )
        )
